use std::collections::HashMap;
use std::hash::Hash;

struct StringInterner {
    storage: Vec<String>, 
    intern_map: HashMap<String, usize>,
}

impl StringInterner {
    fn new() -> Self {
        StringInterner { 
            storage: Vec::new(), 
            intern_map: HashMap::new()
        }
    }

    fn intern(&mut self, key: &str) -> usize {
        let s = key.to_string();
        if let Some(&index) = self.intern_map.get(&s) {
            return index;
        }

        let new_index = self.storage.len();
        self.storage.push(s.clone());
        self.intern_map.insert(s, new_index);
        new_index
    }

    fn get_stored_string(&self, index: usize) -> Option<&str> {
        if index < self.storage.len() {
            Some(&self.storage[index])
        } else {
            None
        }
    }
}

