use std::collections::HashMap;

struct ReplaySystem {
    unique_strings: HashMap<String, usize>,
    string_to_id: HashMap<String, usize>,
}

impl ReplaySystem {
    fn new() -> Self {
        ReplaySystem {
            unique_strings: HashMap::new(),
            string_to_id: HashMap::new(),
        }
    }

    fn register_and_get_id(&mut self, input_str: &str) -> usize {
        if let Some(&id) = self.string_to_id.get(input_str) {
            return id;
        }

        let new_id = self.unique_strings.len();
        self.string_to_id.insert(String::from(input_str), new_id);
        self.unique_strings.insert(String::from(input_str), new_id);
        new_id
    }

    fn record_event(&mut self, action: &str) -> usize {
        println!("Recording event for: {}", action);
        self.register_and_get_id(action)
    }
}

fn main() {
