}

use std::collections::HashMap;
use std::sync::Mutex;

struct StringInterner {
    storage: Mutex<HashMap<String, usize>>,
    next_id: Mutex<usize>,
}

impl StringInterner {
    fn new() -> Self {
        StringInterner {
            storage: Mutex::new(HashMap::new()),
            next_id: Mutex::new(0),
        }
    }

    fn intern(&self, s: &str) -> usize {
        let mut storage = self.storage.lock().unwrap();
        if let Some(&id) = storage.get(s) {
            return id;
        }

        let mut next_id = self.next_id.lock().unwrap();
        let new_id = *next_id;
        *next_id += 1;

        storage.insert(s.to_owned(), new_id);
        new_id
    }
}

