use std::collections::HashMap;
use std::sync::Mutex;

struct SecretStore {
    interned_strings: Mutex<HashMap<String, String>>
}

impl SecretStore {
    fn new() -> Self {
        SecretStore { 
            interned_strings: Mutex::new(HashMap::new())
        }
    }

    fn get_or_intern(&self, key: &str) -> String {
        let mut map = self.interned_strings.lock().unwrap();
        if let Some(existing) = map.get(key) {
            return existing.clone()
        }
        let new_string = key.to_owned();
        map.insert(new_string.clone(), new_string.clone());
        new_string.clone()
    }
}

fn main() {
    let store = SecretStore::new();
    let alg1 = store.get_or_intern("RS256");
    let alg2 = store.get_or_intern("HS256");
    let alg3 = store.get_or_intern("RS256");

    println!("First RS256: {}", alg1);
    println!("Second RS256 (should match first): {}", alg3);
    println!("HS256: {}", alg2);
}

use std::collections::HashMap;

struct Role {
    name: String,
    permissions: Vec<String>,
}

impl From<&str> for Role {
    fn from(s: &str) -> Self {
        Role {
            name: s.to_owned(),
            permissions: vec![s.to_owned()],
        }
    }
}

struct AccessControlSystem {
    roles: HashMap<String, Role>,
}

impl AccessControlSystem {
    fn new() -> Self {
        AccessControlSystem {
            roles: HashMap::new(),
        }
    }

    fn add_role(&mut self, role_name: &str, permissions: Vec<&str>) {
        let mut role = Role { name: role_name.to_owned(), permissions: Vec::new() };
        for p in permissions {
            role.permissions.push(p.to_owned());
        }
        self.roles.insert(role_name.to_owned(), role);
    }

    fn check_access(&self, required_permission: &str) -> bool {
        if let Some(role) = self.roles.values().find(|r| r.name == "admin") {
            return role.permissions.iter().any(|p| p == required_permission);
        }
        false
    }
}

fn main() {
    let mut acs = AccessControlSystem::new();
    acs.add_role("guest", vec!["read:content"]);
    acs.add_role("admin", vec!["read:content", "write:settings"]);

    println!("Can guest read content? {}", acs.check_access("read:content"));
    println!("Can guest write settings? {}", acs.check_access("write:settings"));
}
